  50% { box-shadow: 0 0 25px rgba(57, 255, 20, 0.7), 0 0 40px rgba(57, 255, 20, 0.3); }
  100% { box-shadow: 0 0 5px rgba(57, 255, 20, 0.4); }
}

@keyframes neon-pulse-violet {
  0% { box-shadow: 0 0 5px rgba(168, 85, 247, 0.4); }
  50% { box-shadow: 0 0 25px rgba(168, 85, 247, 0.7), 0 0 40px rgba(168, 85, 247, 0.3); }
  100% { box-shadow: 0 0 5px rgba(168, 85, 247, 0.4); }
}

/* ═══ TAB SWITCHER ═══ */
.tab-switcher {
  display: flex;
  background: rgba(255, 255, 255, 0.05);
  border-radius: 8px;
  padding: 3px;
  gap: 3px;
}

.tab-switcher button {
  background: transparent;
  border: none;
  color: var(--text-muted);
  font-size: 0.65rem;
  font-weight: 800;
  padding: 5px 12px;
  border-radius: 6px;
  cursor: pointer;
  transition: 0.2s;
}

.tab-switcher button.active {
  background: var(--primary);
  color: white;
  box-shadow: 0 0 10px var(--primary);
}

/* ═══ DIAG PANEL ═══ */
.diag-panel {
  display: flex;
  flex-direction: column;
  gap: 1.25rem;
  margin-bottom: 2rem;
}

.diag-item {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.diag-label {
  font-size: 0.75rem;
  font-weight: 600;
  color: var(--text-muted);
  display: flex;
  justify-content: space-between;
}

.diag-label span {
  color: var(--text);
  font-family: monospace;
}

.diag-bar-bg {
  height: 8px;
  background: rgba(255, 255, 255, 0.05);
  border-radius: 4px;
  overflow: hidden;
}

.diag-bar {
  height: 100%;
  border-radius: 4px;
  transition: width 0.5s ease-in-out;
}

.diag-bar.ram {
  background: linear-gradient(90deg, #38bdf8, #0ea5e9);
  box-shadow: 0 0 10px rgba(56, 189, 248, 0.3);
}

.diag-bar.rom {
  background: linear-gradient(90deg, #a855f7, #8b5cf6);
  box-shadow: 0 0 10px rgba(168, 85, 247, 0.3);
}

/* ═══ MODAL ═══ */
.modal-overlay {
  position: fixed;
  top: 0; left: 0; right: 0; bottom: 0;
  background: rgba(0, 0, 0, 0.7);
  backdrop-filter: blur(4px);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 100;
  padding: 1rem;
}

.modal-content {
  background: var(--bg-panel);
  border: 1px solid var(--panel-border);
  border-radius: 24px;
  padding: 2rem;
  width: 92%;
  max-width: 450px;
  max-height: 85vh;
  overflow-y: auto;
  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.5);
}

@media (max-width: 768px) {
  .modal-overlay {
    padding: 0;
    align-items: flex-end;
  }
  .modal-content {
    width: 100%;
    max-width: 100%;
    border-radius: 24px 24px 0 0;
    padding: 1.25rem;
    max-height: 80vh;
    max-height: 80dvh;
  }
}

/* ═══ FORM ELEMENTS ═══ */
.input-field {
  width: 100%;
  padding: 12px 16px;
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid var(--panel-border);
  border-radius: 12px;
  color: var(--text-main);
  font-size: 1rem;
  margin-bottom: 1rem;
  outline: none;
  transition: 0.2s;
}

.input-field:focus {
  border-color: var(--primary);
  box-shadow: 0 0 0 2px rgba(0, 210, 255, 0.2);
}

@media (max-width: 768px) {
  .input-field {
    padding: 10px 14px;
    font-size: 16px;
    border-radius: 10px;
    margin-bottom: 0.75rem;
  }
}

.btn-submit {
  width: 100%;
  padding: 14px;
  background: var(--primary);
  color: #0a0f1a;
  border: none;
  border-radius: 12px;
  font-size: 1rem;
  font-weight: 800;
  cursor: pointer;
  transition: 0.2s;
  touch-action: manipulation;
}

.btn-submit:hover {
  filter: brightness(1.1);
  transform: translateY(-1px);
}

.btn-submit:active {
  transform: scale(0.98);
}

@media (max-width: 768px) {
  .btn-submit {
    padding: 12px;
    font-size: 0.9rem;
    border-radius: 10px;
  }
}

/* ═══ ANIMATIONS ═══ */
@keyframes shuttle-anim {
  0% { transform: translateX(-5px); }
  50% { transform: translateX(5px); }
  100% { transform: translateX(-5px); }
}

.shuttle-anim {
  animation: shuttle-anim 0.5s linear infinite;
}

.pulse-neon {
  position: relative;
}

.pulse-neon::after {
  content: '';
  position: absolute;
  top: -2px; left: -2px; right: -2px; bottom: -2px;
  border-radius: 12px;
  border: 1px solid var(--neon-green);
  opacity: 0;
  animation: ripple 2s infinite;
}

@keyframes ripple {
  0% { transform: scale(1); opacity: 0.5; }
  100% { transform: scale(1.5); opacity: 0; }
}

.chiqish-label {
  position: absolute;
  background: #22c55e;
  padding: 4px 12px;
  border-radius: 6px;
  font-size: 0.65rem;
  font-weight: 800;
  color: #064e3b;
  box-shadow: 0 0 10px rgba(34, 197, 94, 0.3);
}

/* ═══ DASHBOARD STATS ROW (mobile) ═══ */
@media (max-width: 768px) {
  .dashboard-stats-row {
    display: flex;
    gap: 0.5rem;
    margin-bottom: 0.5rem;
    flex-shrink: 0;
    overflow-x: auto;
  }
  .dashboard-stats-row .stat-widget {
    flex: 1;
    min-width: 0;
    padding: 0.5rem;
    margin-bottom: 0;
  }
