.sidebar-desktop {
  width: 240px;
  min-width: 240px;
  background: #111827;
  border-right: 1px solid var(--panel-border);
  display: flex;
  flex-direction: column;
  padding: 1rem;
  overflow-y: auto;
  overflow-x: hidden;
}

/* ═══ MOBILE BOTTOM BAR (iOS 26 / Telegram style) ═══ */
.mobile-bottom-bar {
  display: none;
}

@media (max-width: 768px) {
  .sidebar-desktop {
    display: none;
  }

  .mobile-bottom-bar {
    display: flex;
    position: fixed;
    bottom: 0;
    left: 0;
    right: 0;
    z-index: 999;
    background: rgba(17, 24, 39, 0.85);
    backdrop-filter: blur(20px) saturate(180%);
    -webkit-backdrop-filter: blur(20px) saturate(180%);
    border-top: 0.5px solid rgba(255, 255, 255, 0.1);
    padding-bottom: env(safe-area-inset-bottom, 0px);
  }

  .mobile-bottom-bar-inner {
    display: flex;
    width: 100%;
    justify-content: space-around;
    align-items: flex-end;
    padding: 6px 4px 4px;
    gap: 0;
  }

  .mobile-tab-btn {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 2px;
    background: none;
    border: none;
    cursor: pointer;
    padding: 4px 6px;
    border-radius: 12px;
    color: rgba(148, 163, 184, 0.7);
    transition: all 0.2s ease;
    min-width: 52px;
    -webkit-tap-highlight-color: transparent;
    position: relative;
  }

  .mobile-tab-btn:active {
    transform: scale(0.9);
  }

  .mobile-tab-icon-wrap {
    display: flex;
