{"tool":"newFileCreated","path":"frontend/src/index.css","content":":root {
  --bg: #05070a;
  --bg-panel: #0b0f1a;
  --card: rgba(15, 23, 42, 0.6);
  --panel-border: rgba(255, 255, 255, 0.08);
  --primary: #00d2ff;
  --neon-blue: #00d2ff;
  --neon-green: #39ff14;
  --neon-red: #ff3131;
  --neon-yellow: #ffea00;
  --neon-violet: #a855f7;
  --text-main: #f8fafc;
  --text-muted: #64748b;
  --glass: rgba(10, 15, 25, 0.7);
}

html, body {
  margin: 0;
  padding: 0;
  background-color: var(--bg);
  background-image: radial-gradient(circle at 50% 50%, #1e293b 0%, #05070a 100%);
  color: var(--text-main);
  font-family: 'Inter', sans-serif;
  overflow: hidden;
  -webkit-text-size-adjust: 100%;
  -webkit-tap-highlight-color: transparent;
  width: 100%;
  height: 100%;
}

* {
  box-sizing: border-box;
}

/* ═══ SPLASH SCREEN ═══ */
.splash-screen {
  position: fixed;
  top: 0; left: 0; right: 0; bottom: 0;
  background: #000;
  z-index: 9999;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: opacity 0.6s ease;
}

.splash-screen.splash-fade-out {
  opacity: 0;
  pointer-events: none;
}

.splash-video {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

/* ═══ APP APPEAR ANIMATION ═══ */
.app-appear {
  animation: app-fade-in 0.8s ease forwards;
}

@keyframes app-fade-in {
  0% { opacity: 0; transform: scale(0.98); }
  100% { opacity: 1; transform: scale(1); }
}

/* ═══ APP LAYOUT ═══ */
.app-container {
  display: flex;
  height: 100vh;
  height: 100dvh;
  width: 100vw;
  overflow: hidden;
}

@media (max-width: 768px) {
  .app-container {
    flex-direction: column;
    height: 100dvh;
    width: 100vw;
    overflow: hidden;
  }
}

/* ═══ DESKTOP SIDEBAR ═══ */
.sidebar-desktop {
  width: 240px;
  min-width: 240px;
  background: #111827;
  border-right: 1px solid var(--panel-border);
  display: flex;
  flex-direction: column;
  padding: 1rem;
  overflow-y: auto;
  overflow-x: hidden;
}

/* ═══ MOBILE BOTTOM BAR (iOS 26 / Telegram style) ═══ */
.mobile-bottom-bar {
  display: none;
}

@media (max-width: 768px) {
  .sidebar-desktop {
    display: none;
  }

  .mobile-bottom-bar {
    display: flex;
