    align-items: flex-end;
    padding: 6px 4px 4px;
    gap: 0;
  }

  .mobile-tab-btn {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 2px;
    background: none;
    border: none;
    cursor: pointer;
    padding: 4px 6px;
    border-radius: 12px;
    color: rgba(148, 163, 184, 0.7);
    transition: all 0.2s ease;
    min-width: 52px;
    -webkit-tap-highlight-color: transparent;
    position: relative;
  }

  .mobile-tab-btn:active {
    transform: scale(0.9);
  }

  .mobile-tab-icon-wrap {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 28px;
    height: 28px;
    border-radius: 50%;
    transition: all 0.25s ease;
  }

  .mobile-tab-btn.active .mobile-tab-icon-wrap {
    background: rgba(0, 210, 255, 0.15);
    color: var(--primary);
  }

  .mobile-tab-btn.active {
    color: var(--primary);
  }

  .mobile-tab-label {
    font-size: 0.55rem;
    font-weight: 600;
    letter-spacing: 0.2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    max-width: 64px;
  }

  .mobile-tab-btn.active .mobile-tab-label {
    color: var(--primary);
    font-weight: 700;
  }

  .mobile-tab-btn.logout-btn {
    color: rgba(239, 68, 68, 0.7);
