import axios from 'axios';
import { LogIn } from 'lucide-react';

const Login = ({ onLogin }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      const response = await axios.post(`http://${window.location.hostname}:8000/token`, 
        new URLSearchParams({ username, password }),
        { headers: { 'Content-Type': 'application/x-www-form-urlencoded' } }
      );
      const token = response.data.access_token;
      localStorage.setItem('token', token);

      const userResponse = await axios.get(`http://${window.location.hostname}:8000/users/me`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      onLogin(userResponse.data);
    } catch (err) {
      setError('Login yoki parol xato');
      setLoading(false);
    }
  };

  return (
    <div className="login-page">
      <form onSubmit={handleSubmit} className="login-card">
        <div className="login-header">
          <div className="login-icon">
            <LogIn size={36} color="#38bdf8" />
          </div>
          <h2 className="login-title">SMART ESP32</h2>
          <p className="login-subtitle">Industrial Monitoring Portal</p>
        </div>

        {error && <div className="login-error">{error}</div>}

        <div className="login-field">
          <label>Foydalanuvchi</label>
          <input 
            type="text" 
            placeholder="Login kiriting"
            value={username} 
            onChange={(e) => setUsername(e.target.value)} 
            required 
            autoFocus
          />
        </div>

        <div className="login-field">
          <label>Parol</label>
          <input 
            type="password" 
            placeholder="Parol kiriting"
            value={password} 
            onChange={(e) => setPassword(e.target.value)} 
            required 
          />
        </div>

        <button type="submit" className="btn-submit login-btn" disabled={loading}>
          {loading ? 'Kutilmoqda...' : 'Kirish'}
        </button>
      </form>
    </div>
  );
};

