{"tool":"newFileCreated","path":"frontend/src/index.css","content":":root {
  --bg: #05070a;
  --bg-panel: #0b0f1a;
  --card: rgba(15, 23, 42, 0.6);
  --panel-border: rgba(255, 255, 255, 0.08);
  --primary: #00d2ff;
  --neon-blue: #00d2ff;
  --neon-green: #39ff14;
  --neon-red: #ff3131;
  --neon-yellow: #ffea00;
  --neon-violet: #a855f7;
  --text-main: #f8fafc;
  --text-muted: #64748b;
  --glass: rgba(10, 15, 25, 0.7);
}

html, body {
  margin: 0;
  padding: 0;
  background-color: var(--bg);
  background-image: radial-gradient(circle at 50% 50%, #1e293b 0%, #05070a 100%);
  color: var(--text-main);
  font-family: 'Inter', sans-serif;
  overflow: hidden;
  -webkit-text-size-adjust: 100%;
  -webkit-tap-highlight-color: transparent;
  width: 100%;
  height: 100%;
}

* {
  box-sizing: border-box;
}

/* ═══ SPLASH SCREEN ═══ */
.splash-screen {
  position: fixed;
  top: 0; left: 0; right: 0; bottom: 0;
  background: #000;
  z-index: 9999;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: opacity 0.6s ease;
}

.splash-screen.splash-fade-out {
  opacity: 0;
  pointer-events: none;
}

.splash-video {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

/* ═══ APP APPEAR ANIMATION ═══ */
.app-appear {
  animation: app-fade-in 0.8s ease forwards;
}

@keyframes app-fade-in {
  0% { opacity: 0; transform: scale(0.98); }
  100% { opacity: 1; transform: scale(1); }
}

/* ═══ APP LAYOUT ═══ */
.app-container {
  display: flex;
  height: 100vh;
  height: 100dvh;
  width: 100vw;
  overflow: hidden;
}

@media (max-width: 768px) {
  .app-container {
    flex-direction: column;
    height: 100dvh;
    width: 100vw;
    overflow: hidden;
  }
}

/* ═══ LOGIN PAGE ═══ */
.login-page {
  display: flex;
  align-items: center;
  justify-content: center;
  height: 100vh;
  height: 100dvh;
  width: 100vw;
  background: var(--bg);
  background-image: radial-gradient(circle at 50% 50%, #1e293b 0%, #05070a 100%);
  padding: 1rem;
}

.login-card {
  background: var(--bg-panel);
  border: 1px solid var(--panel-border);
  border-radius: 24px;
  padding: 2rem;
  width: 100%;
  max-width: 380px;
  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.5);
  animation: app-fade-in 0.6s ease forwards;
}

.login-header {
  text-align: center;
  margin-bottom: 1.5rem;
}

.login-icon {
  background: rgba(56, 189, 248, 0.1);
  width: 72px;
  height: 72px;
  border-radius: 20px;
  display: flex;
  align-items: center;
  justify-content: center;
  margin: 0 auto 1rem;
}

.login-title {
  font-size: 1.4rem;
  font-weight: 900;
  margin: 0;
  color: var(--primary);
  letter-spacing: -0.5px;
}

.login-subtitle {
  color: var(--text-muted);
  font-size: 0.8rem;
  margin: 0.25rem 0 0;
  text-transform: uppercase;
  letter-spacing: 1px;
}

.login-error {
  background: rgba(239, 68, 68, 0.1);
  border: 1px solid rgba(239, 68, 68, 0.3);
  color: #f87171;
  padding: 0.5rem 0.75rem;
  border-radius: 10px;
  font-size: 0.8rem;
  font-weight: 600;
  margin-bottom: 1rem;
  text-align: center;
}

.login-field {
  margin-bottom: 1rem;
}

.login-field label {
  display: block;
  font-size: 0.75rem;
  font-weight: 700;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-bottom: 0.4rem;
}

.login-field input {
  width: 100%;
  padding: 12px 16px;
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid var(--panel-border);
  border-radius: 12px;
  color: var(--text-main);
  font-size: 16px;
  outline: none;
  transition: 0.2s;
}

.login-field input:focus {
  border-color: var(--primary);
  box-shadow: 0 0 0 2px rgba(0, 210, 255, 0.2);
}

.login-field input::placeholder {
  color: var(--text-muted);
  opacity: 0.5;
}

.login-btn {
  margin-top: 0.5rem;
}

.login-btn:disabled {
  opacity: 0.6;
  cursor: not-allowed;
}

@media (max-width: 768px) {
  .login-card {
    padding: 1.5rem;
    border-radius: 20px;
    max-width: 100%;
  }
  .login-icon {
    width: 60px;
    height: 60px;
    border-radius: 16px;
  }
  .login-icon svg {
    width: 28px;
    height: 28px;
  }
  .login-title {
    font-size: 1.2rem;
  }
  .login-field input {
    padding: 10px 14px;
    border-radius: 10px;
  }
}

/* ═══ DESKTOP SIDEBAR ═══ */
.sidebar-desktop {
  width: 240px;
  min-width: 240px;
  background: #111827;
  border-right: 1px solid var(--panel-border);
  display: flex;
  flex-direction: column;
  padding: 1rem;
  overflow-y: auto;
  overflow-x: hidden;
}

/* ═══ MOBILE BOTTOM BAR (iOS 26 / Telegram style) ═══ */
.mobile-bottom-bar {
  display: none;
}

@media (max-width: 768px) {
  .sidebar-desktop {
    display: none;
  }

  .mobile-bottom-bar {
    display: flex;
    position: fixed;
    bottom: 0;
    left: 0;
    right: 0;
    z-index: 999;
    background: rgba(17, 24, 39, 0.85);
    backdrop-filter: blur(20px) saturate(180%);
    -webkit-backdrop-filter: blur(20px) saturate(180%);
    border-top: 0.5px solid rgba(255, 255, 255, 0.1);
    padding-bottom: env(safe-area-inset-bottom, 0px);
  }

  .mobile-bottom-bar-inner {
    display: flex;
    width: 100%;
    justify-content: space-around;
    align-items: flex-end;
    padding: 6px 4px 4px;
    gap: 0;
  }

  .mobile-tab-btn {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 2px;
    background: none;
    border: none;
    cursor: pointer;
    padding: 4px 6px;
    border-radius: 12px;
    color: rgba(148, 163, 184, 0.7);
    transition: all 0.2s ease;
    min-width: 52px;
    -webkit-tap-highlight-color: transparent;
    position: relative;
  }

  .mobile-tab-btn:active {
    transform: scale(0.9);
  }

  .mobile-tab-icon-wrap {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 28px;
    height: 28px;
    border-radius: 50%;
    transition: all 0.25s ease;
  }

  .mobile-tab-btn.active .mobile-tab-icon-wrap {
    background: rgba(0, 210, 255, 0.15);
    color: var(--primary);
  }

  .mobile-tab-btn.active {
    color: var(--primary);
  }

  .mobile-tab-label {
    font-size: 0.55rem;
    font-weight: 600;
    letter-spacing: 0.2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    max-width: 64px;
  }

  .mobile-tab-btn.active .mobile-tab-label {
    color: var(--primary);
    font-weight: 700;
  }

  .mobile-tab-btn.logout-btn {
    color: rgba(239, 68, 68, 0.7);
  }

  .mobile-tab-btn.logout-btn:active {
    color: #ef4444;
  }
}

/* ═══ STAT WIDGETS ═══ */
.stat-widget {
  background: var(--card);
  border-radius: 1rem;
  padding: 1.25rem;
  margin-bottom: 1rem;
  border: 1px solid var(--panel-border);
}

.stat-value {
  font-size: 2rem;
  font-weight: 800;
  line-height: 1;
}

.stat-label {
  color: var(--text-muted);
  font-size: 0.875rem;
  text-transform: uppercase;
  letter-spacing: 1px;
}

@media (max-width: 768px) {
  .stat-widget {
    padding: 0.5rem;
    margin-bottom: 0;
    border-radius: 0.75rem;
  }
  .stat-value {
    font-size: 1.2rem;
  }
  .stat-label {
    font-size: 0.6rem;
    letter-spacing: 0;
  }
}

/* ═══ MAIN CONTENT ═══ */
.main-content {
  flex: 1;
  padding: 1rem;
  background: #0b0f1a;
  overflow: auto;
  display: flex;
  flex-direction: column;
  min-width: 0;
  min-height: 0;
}

@media (max-width: 768px) {
  .main-content {
    padding: 0.25rem 0.25rem 72px 0.25rem;
    flex: 1;
    overflow: hidden;
    display: flex;
    flex-direction: column;
    min-height: 0;
  }
}

/* ═══ FACTORY MAP ═══ */
.factory-map-container {
  flex: 1;
  overflow: auto;
  border-radius: 16px;
  padding: 8px;
  position: relative;
}

@media (max-width: 768px) {
  .factory-map-container {
    border-radius: 8px;
    padding: 0;
    overflow: auto;
    -webkit-overflow-scrolling: touch;
    flex: 1;
    min-height: 0;
  }
}

.factory-bg {
  position: relative;
  width: 1200px;
  height: 800px;
  background: #111827;
  border-radius: 8px;
  border: 3px solid #334155;
  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.5);
  background-image: 
    linear-gradient(rgba(255,255,255,0.02) 1px, transparent 1px),
    linear-gradient(90deg, rgba(255,255,255,0.02) 1px, transparent 1px);
  background-size: 25px 25px;
}

@media (max-width: 768px) {
  .factory-bg {
    width: 1200px;
    height: 800px;
    transform: scale(0.55);
    transform-origin: top left;
    border-radius: 6px;
    border-width: 2px;
  }
}

@media (max-width: 480px) {
  .factory-bg {
    transform: scale(0.4);
    transform-origin: top left;
  }
}

.zone-label {
  position: absolute;
  color: var(--text-muted);
  font-weight: 700;
  font-size: 0.9rem;
  pointer-events: none;
  text-transform: uppercase;
  letter-spacing: 3px;
  opacity: 0.5;
}

/* ═══ MACHINE NODES ═══ */
.machine-node {
  position: absolute;
  width: 48px;
  height: 48px;
  border-radius: 12px;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  border: 1px solid rgba(255, 255, 255, 0.1);
  backdrop-filter: blur(4px);
  touch-action: manipulation;
}

.machine-node:hover {
  transform: scale(1.2) translateY(-5px);
  z-index: 10;
  box-shadow: 0 0 20px rgba(0, 210, 255, 0.5);
}

.machine-node.is-focused {
  border-color: var(--primary);
  box-shadow: 0 0 30px rgba(0, 210, 255, 0.6);
  z-index: 5;
}

.smart-pulse {
  position: absolute;
  width: 100%;
  height: 100%;
  border: 2px solid var(--primary);
  border-radius: 50%;
  animation: smart-ripple 1.5s infinite;
  pointer-events: none;
}

@keyframes smart-ripple {
  0% { transform: scale(0.5); opacity: 1; }
  100% { transform: scale(2.5); opacity: 0; }
}

.machine-node.running {
  background: rgba(57, 255, 20, 0.1);
  color: var(--neon-green);
  border-color: var(--neon-green);
  box-shadow: 0 0 10px rgba(57, 255, 20, 0.2);
  animation: neon-pulse-green 2s infinite;
}

.machine-node.stopped {
  background: rgba(255, 49, 49, 0.1);
  color: var(--neon-red);
  border-color: var(--neon-red);
}

.machine-node.warning {
  background: rgba(255, 234, 0, 0.1);
  color: var(--neon-yellow);
  border-color: var(--neon-yellow);
  animation: neon-pulse-yellow 2s infinite;
}

.machine-node.searching {
  background: rgba(168, 85, 247, 0.2);
  color: #c084fc;
  border-color: #a855f7;
  box-shadow: 0 0 15px rgba(168, 85, 247, 0.4);
  animation: neon-pulse-violet 2s infinite;
}

.searching .icon {
  animation: searching-rotate 2s linear infinite;
}

@keyframes searching-rotate {
  0% { transform: scale(1); opacity: 0.7; }
  50% { transform: scale(1.1); opacity: 1; }
  100% { transform: scale(1); opacity: 0.7; }
}

@keyframes neon-pulse-green {
  0% { box-shadow: 0 0 5px rgba(57, 255, 20, 0.4); }
  50% { box-shadow: 0 0 25px rgba(57, 255, 20, 0.7), 0 0 40px rgba(57, 255, 20, 0.3); }
  100% { box-shadow: 0 0 5px rgba(57, 255, 20, 0.4); }
}

@keyframes neon-pulse-violet {
  0% { box-shadow: 0 0 5px rgba(168, 85, 247, 0.4); }
  50% { box-shadow: 0 0 25px rgba(168, 85, 247, 0.7), 0 0 40px rgba(168, 85, 247, 0.3); }
  100% { box-shadow: 0 0 5px rgba(168, 85, 247, 0.4); }
}

/* ═══ TAB SWITCHER ═══ */
.tab-switcher {
  display: flex;
  background: rgba(255, 255, 255, 0.05);
  border-radius: 8px;
  padding: 3px;
  gap: 3px;
}

.tab-switcher button {
  background: transparent;
  border: none;
  color: var(--text-muted);
  font-size: 0.65rem;
  font-weight: 800;
  padding: 5px 12px;
  border-radius: 6px;
  cursor: pointer;
  transition: 0.2s;
}

.tab-switcher button.active {
  background: var(--primary);
  color: white;
  box-shadow: 0 0 10px var(--primary);
}

/* ═══ DIAG PANEL ═══ */
.diag-panel {
  display: flex;
  flex-direction: column;
  gap: 1.25rem;
  margin-bottom: 2rem;
}

.diag-item {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.diag-label {
  font-size: 0.75rem;
  font-weight: 600;
  color: var(--text-muted);
  display: flex;
  justify-content: space-between;
}

.diag-label span {
  color: var(--text);
  font-family: monospace;
}

.diag-bar-bg {
  height: 8px;
  background: rgba(255, 255, 255, 0.05);
  border-radius: 4px;
  overflow: hidden;
}

.diag-bar {
  height: 100%;
  border-radius: 4px;
  transition: width 0.5s ease-in-out;
}

.diag-bar.ram {
  background: linear-gradient(90deg, #38bdf8, #0ea5e9);
  box-shadow: 0 0 10px rgba(56, 189, 248, 0.3);
}

.diag-bar.rom {
  background: linear-gradient(90deg, #a855f7, #8b5cf6);
  box-shadow: 0 0 10px rgba(168, 85, 247, 0.3);
}

/* ═══ MODAL ═══ */
.modal-overlay {
  position: fixed;
  top: 0; left: 0; right: 0; bottom: 0;
  background: rgba(0, 0, 0, 0.7);
  backdrop-filter: blur(4px);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 100;
  padding: 1rem;
}

.modal-content {
  background: var(--bg-panel);
  border: 1px solid var(--panel-border);
  border-radius: 24px;
  padding: 2rem;
  width: 92%;
  max-width: 450px;
  max-height: 85vh;
  overflow-y: auto;
  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.5);
}

@media (max-width: 768px) {
  .modal-overlay {
    padding: 0;
    align-items: flex-end;
  }
  .modal-content {
    width: 100%;
    max-width: 100%;
    border-radius: 24px 24px 0 0;
    padding: 1.25rem;
    max-height: 80vh;
    max-height: 80dvh;
  }
}

/* ═══ FORM ELEMENTS ═══ */
.input-field {
  width: 100%;
  padding: 12px 16px;
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid var(--panel-border);
  border-radius: 12px;
  color: var(--text-main);
  font-size: 1rem;
  margin-bottom: 1rem;
  outline: none;
  transition: 0.2s;
}

.input-field:focus {
  border-color: var(--primary);
  box-shadow: 0 0 0 2px rgba(0, 210, 255, 0.2);
}

@media (max-width: 768px) {
  .input-field {
    padding: 10px 14px;
    font-size: 16px;
    border-radius: 10px;
    margin-bottom: 0.75rem;
  }
}

.btn-submit {
  width: 100%;
  padding: 14px;
  background: var(--primary);
  color: #0a0f1a;
  border: none;
  border-radius: 12px;
  font-size: 1rem;
  font-weight: 800;
  cursor: pointer;
  transition: 0.2s;
  touch-action: manipulation;
}

.btn-submit:hover {
  filter: brightness(1.1);
  transform: translateY(-1px);
}

.btn-submit:active {
  transform: scale(0.98);
}

@media (max-width: 768px) {
  .btn-submit {
    padding: 12px;
    font-size: 0.9rem;
    border-radius: 10px;
  }
}

/* ═══ ANIMATIONS ═══ */
@keyframes shuttle-anim {
  0% { transform: translateX(-5px); }
  50% { transform: translateX(5px); }
  100% { transform: translateX(-5px); }
}

.shuttle-anim {
  animation: shuttle-anim 0.5s linear infinite;
}

.pulse-neon {
  position: relative;
}

.pulse-neon::after {
  content: '';
  position: absolute;
  top: -2px; left: -2px; right: -2px; bottom: -2px;
  border-radius: 12px;
  border: 1px solid var(--neon-green);
  opacity: 0;
  animation: ripple 2s infinite;
}

@keyframes ripple {
  0% { transform: scale(1); opacity: 0.5; }
  100% { transform: scale(1.5); opacity: 0; }
}

.chiqish-label {
