    padding: 10px 14px;
    border-radius: 10px;
  }
}

/* ═══ DESKTOP SIDEBAR ═══ */
.sidebar-desktop {
  width: 240px;
  min-width: 240px;
  background: #111827;
  border-right: 1px solid var(--panel-border);
  display: flex;
  flex-direction: column;
  padding: 1rem;
  overflow-y: auto;
  overflow-x: hidden;
}

