@media (max-width: 768px) {
  .sidebar-desktop {
    display: none;
  }

  .mobile-bottom-bar {
    display: flex;
    position: fixed;
    bottom: 0;
    left: 0;
    right: 0;
    z-index: 999;
    background: rgba(17, 24, 39, 0.85);
