import InteractiveMap from './InteractiveMap';
import axios from 'axios';
import { emitRefresh } from '../utils/events';

const Dashboard = ({ user }) => {
  const [machines, setMachines] = useState([]);
  const [selectedMachine, setSelectedMachine] = useState(null);
  const [asnovaLength, setAsnovaLength] = useState("");
  const [activeTab, setActiveTab] = useState('info');

  useEffect(() => {
    const fetchMachines = async () => {
      try {
        const token = localStorage.getItem("token");
        if (!token) return;
        const res = await fetch(`http://${window.location.hostname}:8000/machines`, {
          headers: { "Authorization": `Bearer ${token}` }
        });
        if (res.ok) {
          const data = await res.json();
          if (data.length > 0) setMachines(data);
        }
      } catch (e) {}
    };

    fetchMachines();
    const interval = setInterval(fetchMachines, 2000);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    if (selectedMachine) {
      fetch(`http://${window.location.hostname}:8000/machines/${selectedMachine.id}/watch`, {
        method: "POST",
        headers: { "Authorization": `Bearer ${localStorage.getItem("token")}` }
      }).catch(err => console.error("Watch trigger failed", err));
    }
  }, [selectedMachine]);

  const handleFillAsnova = async () => {
    if (!asnovaLength || !selectedMachine) return;
    try {
      const response = await fetch(`http://${window.location.hostname}:8000/machines/${selectedMachine.id}/fill`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${localStorage.getItem("token")}`
        },
        body: JSON.stringify({
          initial_asnova_length: parseFloat(asnovaLength),
          last_operator_id: user.id
        })
      });
      if (response.ok) {
        alert("Asnova muvaffaqiyatli toldirildi!");
        setSelectedMachine(null);
        setAsnovaLength("");
        emitRefresh();
      }
    } catch (err) {
      alert("Xatolik yuz berdi");
    }
  };

  const handleSourceChange = async (machineId, newSource) => {
    try {
      await axios.post(`http://${window.location.hostname}:8000/machines/${machineId}/source?preferred_source=${newSource}`, {}, {
        headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
      });
    } catch (err) {
      alert("Xatolik: Manbani o'zgartirib bo'lmadi");
    }
  };

  const stats = useMemo(() => ({
    total: 68,
    running: machines.filter(m => m.status === 'RUNNING').length,
    stopped: machines.filter(m => m.status === 'ASNOVA_EMPTY' || m.status === 'STOPPED' || m.status === 'OFFLINE').length
  }), [machines]);

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* Stats Bar */}
      <div className="dashboard-stats-row" style={{ display: 'flex', gap: '1rem', marginBottom: '1rem', flexShrink: 0 }}>
        <div className="stat-widget" style={{ flex: 1, margin: 0 }}>
          <div className="stat-label">Jami Stanoklar</div>
          <div className="stat-value">{stats.total}</div>
        </div>
        <div className="stat-widget" style={{ flex: 1, margin: 0 }}>
          <div className="stat-label" style={{ color: 'var(--success)' }}>Ishlamoqda</div>
          <div className="stat-value" style={{ color: 'var(--success)' }}>{stats.running}</div>
        </div>
        <div className="stat-widget" style={{ flex: 1, margin: 0 }}>
          <div className="stat-label" style={{ color: 'var(--danger)' }}>To'xtagan</div>
          <div className="stat-value" style={{ color: 'var(--danger)' }}>{stats.stopped}</div>
        </div>
        <div className="stat-widget" style={{ flex: 1, margin: 0, borderLeft: '4px solid var(--blue)' }}>
          <div className="stat-label">Signal (S1)</div>
          <div style={{ fontSize: '1.1rem', fontWeight: 700, marginTop: '5px' }}>
            {machines.find(m => m.id === 'S1')?.baud || 0} BPS
          </div>
        </div>
      </div>

      {/* Map */}
      <div className="factory-map-container" style={{ flex: 1 }}>
        <InteractiveMap 
          machines={machines} 
          selectedMachine={selectedMachine}
          onSelectMachine={(m) => {
            setSelectedMachine(m);
            setActiveTab('info');
          }} 
        />
      </div>

      {/* Detailed Machine Info Modal */}
      {selectedMachine && (
        <div className="modal-overlay" onClick={() => setSelectedMachine(null)}>
          <div className="modal-content" onClick={e => e.stopPropagation()}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
              <h2 style={{ margin: 0, fontSize: '1.3rem' }}>Stanok {selectedMachine.id}</h2>
              <div className="tab-switcher">
                <button 
                  className={activeTab === 'info' ? 'active' : ''} 
                  onClick={() => setActiveTab('info')}
                >INFO</button>
                <button 
                  className={activeTab === 'diag' ? 'active' : ''} 
                  onClick={() => setActiveTab('diag')}
                >DIAG</button>
              </div>
            </div>

            {selectedMachine.id === 'S1' && (
              <div style={{ marginBottom: '1rem', display: 'flex', gap: '0.5rem', alignItems: 'center', background: 'rgba(255,255,255,0.05)', padding: '0.75rem', borderRadius: '12px' }}>
                <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)', fontWeight: 600, textTransform: 'uppercase', width: '80px' }}>Ulanish</div>
                <div style={{ display: 'flex', flex: 1, gap: '2px', background: 'rgba(0,0,0,0.3)', padding: '2px', borderRadius: '8px' }}>
                  {['AUTO', 'USB', 'WIFI'].map(src => (
                    <button 
                      key={src}
                      onClick={() => handleSourceChange(selectedMachine.id, src)}
                      style={{ 
                        flex: 1, 
                        padding: '6px', 
                        fontSize: '0.65rem', 
                        borderRadius: '6px',
                        background: selectedMachine.preferred_source === src ? 'var(--primary)' : 'transparent',
                        color: selectedMachine.preferred_source === src ? 'black' : 'white',
                        border: 'none',
                        cursor: 'pointer',
                        fontWeight: 700
                      }}
                    >{src}</button>
                  ))}
                </div>
              </div>
            )}

           {activeTab === 'info' ? (
             <>
               <div style={{ marginBottom: '1rem', padding: '0.75rem', background: 'rgba(0,0,0,0.2)', borderRadius: '12px' }}>
                 <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>Holat</div>
                 <div style={{ fontSize: '1rem', fontWeight: 800, color: selectedMachine.displayStatus?.includes('aloqa') ? 'var(--neon-red)' : 'var(--neon-green)', display: 'flex', justifyContent: 'space-between', flexWrap: 'wrap', gap: '4px' }}>
                   <span>{selectedMachine.displayStatus}</span>
                   <span style={{ fontSize: '0.65rem', opacity: 0.6 }}>Mode: {selectedMachine.connection_source}</span>
                 </div>
               </div>

               <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '0.5rem', marginBottom: '1rem' }}>
                 <div className="stat-widget" style={{ margin: 0, padding: '0.75rem' }}>
                   <div className="stat-label" style={{ fontSize: '0.6rem' }}>Smena</div>
                   <div className="stat-value" style={{ fontSize: '1rem' }}>{selectedMachine.shift_meters?.toFixed(1) || 0}m</div>
                 </div>
                 <div className="stat-widget" style={{ margin: 0, padding: '0.75rem' }}>
                   <div className="stat-label" style={{ fontSize: '0.6rem' }}>Asnova</div>
                   <div className="stat-value" style={{ fontSize: '1rem' }}>{selectedMachine.remaining?.toFixed(1) || 0}m</div>
                 </div>
                 <div className="stat-widget" style={{ margin: 0, padding: '0.75rem' }}>
                   <div className="stat-label" style={{ fontSize: '0.6rem' }}>Baud</div>
                   <div className="stat-value" style={{ fontSize: '1rem' }}>{selectedMachine.baud || 0}</div>
                 </div>
               </div>

               {(selectedMachine.remaining <= 0 || user.role === 'ADMIN' || user.role === 'UZLAVYAZ') && (
                 <div style={{ marginBottom: '1rem' }}>
                   <label style={{ fontSize: '0.75rem', fontWeight: 600, color: 'var(--text-muted)', textTransform: 'uppercase' }}>
                     Yangi Asnova Uzunligi (metr)
                   </label>
                   <input
                     type="number"
                     className="input-field"
                     placeholder="Masalan: 5000"
                     autoFocus
                     value={asnovaLength}
                     onChange={(e) => setAsnovaLength(e.target.value)}
                   />
                   <button 
                     className="btn-submit" 
                     onClick={handleFillAsnova}
                     style={{ background: 'var(--neon-green)', color: '#064e3b' }}
                   >
                     To'ldirish
                   </button>
                 </div>
               )}
             </>
           ) : (
              <div className="diag-panel" style={{ marginBottom: '1rem' }}>
                 <div className="diag-item">
                   <div className="diag-label">RAM (Heap) <span>{((selectedMachine.sys_info?.ram?.free / 1048576) || 0).toFixed(2)} MB / {((selectedMachine.sys_info?.ram?.total / 1048576) || 0).toFixed(2)} MB</span></div>
                   <div className="diag-bar-bg">
                     <div className="diag-bar ram" style={{ width: `${(selectedMachine.sys_info?.ram?.total ? (selectedMachine.sys_info.ram.free / selectedMachine.sys_info.ram.total * 100) : 0)}%` }}></div>
                   </div>
                 </div>

                 <div className="diag-item">
                   <div className="diag-label">ROM (Flash) <span>{((selectedMachine.sys_info?.rom?.free / 1048576) || 0).toFixed(2)} MB / {((selectedMachine.sys_info?.rom?.total / 1048576) || 0).toFixed(2)} MB</span></div>
                   <div className="diag-bar-bg">
                     <div className="diag-bar rom" style={{ width: `${(selectedMachine.sys_info?.rom?.total ? (selectedMachine.sys_info.rom.free / selectedMachine.sys_info.rom.total * 100) : 0)}%` }}></div>
                   </div>
                 </div>

                 <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.5rem' }}>
                   <div className="stat-widget" style={{ margin: 0, background: 'rgba(56, 189, 248, 0.05)', padding: '0.75rem' }}>
                     <div className="stat-label" style={{ fontSize: '0.6rem' }}>CPU Speed</div>
                     <div className="stat-value" style={{ fontSize: '0.9rem', color: 'var(--neon-blue)' }}>{selectedMachine.sys_info?.cpu || 0} MHz</div>
                   </div>
                   <div className="stat-widget" style={{ margin: 0, background: 'rgba(168, 85, 247, 0.05)', padding: '0.75rem' }}>
                     <div className="stat-label" style={{ fontSize: '0.6rem' }}>WiFi RSSI</div>
                     <div className="stat-value" style={{ fontSize: '0.9rem', color: '#a855f7' }}>{selectedMachine.sys_info?.wifi?.rssi || 0} dBm</div>
                   </div>
                 </div>

                 <div className="stat-widget" style={{ margin: '0.5rem 0', background: 'rgba(255,255,255,0.03)', padding: '0.75rem' }}>
                   <div className="stat-label" style={{ fontSize: '0.6rem' }}>Connected SSID</div>
                   <div className="stat-value" style={{ fontSize: '0.85rem' }}>{selectedMachine.sys_info?.wifi?.ssid || 'N/A'}</div>
                 </div>
              </div>
           )}

           <button 
             className="btn-submit" 
             onClick={() => setSelectedMachine(null)}
             style={{ background: '#334155', color: 'white', marginTop: '0.25rem' }}
           >
             Yopish
           </button>
          </div>
        </div>
      )}
    </div>
  );
};

