  text-align: center;
}
.login-field { margin-bottom: 1rem; }
.login-field label {
  display: block; font-size: 0.75rem; font-weight: 600;
  color: var(--text-muted); margin-bottom: 4px;
}
.login-field input {
  width: 100%; padding: 12px 16px;
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid var(--panel-border);
  border-radius: 12px; color: var(--text-main);
  font-size: 16px; outline: none; transition: 0.2s;
}
.login-field input:focus {
  border-color: var(--primary);
  box-shadow: 0 0 0 2px rgba(0, 210, 255, 0.2);
}
.login-btn { margin-top: 0.5rem; }
@media (max-width: 768px) {
  .login-card { padding: 1.5rem; border-radius: 20px; }
  .login-icon { width: 60px; height: 60px; }
  .login-title { font-size: 1.1rem; }
}

/* ═══ MOBILE PANEL OVERRIDES ═══ */
@media (max-width: 768px) {
  .main-content > div { padding: 0.5rem !important; }
  .main-content h2 { font-size: 1.1rem !important; margin-bottom: 0.75rem !important; }
  .main-content h3 { font-size: 0.9rem !important; }
  .main-content table {
    display: block;
    overflow-x: auto;
    -webkit-overflow-scrolling: touch;
    min-width: 500px;
