{"tool":"newFileCreated","path":"frontend/src/components/MechanicPanel.jsx","content":"import React, { useState, useEffect, useRef } from 'react';
import { Wrench, Clock, CheckCircle, AlertTriangle, ArrowRight } from 'lucide-react';
import { emitRefresh } from '../utils/events';

const SIGNAL_TYPES = [
  { value: 'MECHANIC', label: 'Mexanik', color: '#f59e0b', icon: '🔧' },
  { value: 'ELECTRIC', label: 'Elektrik', color: '#3b82f6', icon: '⚡' },
  { value: 'ASNOVA', label: 'Asnova', color: '#a855f7', icon: '🧵' },
];

const REASONS = {
  MECHANIC: [
    'Kamar uzildi', 'Galtak buzildi', 'Encoder buzildi', 'Podshipnik yemirildi',
    "Yog' yetishmayapti", "Tishli g'ildirak buzildi", 'Servomotor hatoligi', 'Boshqa'
  ],
  ELECTRIC: [
    'Motor ishlamayabdi', 'Tugmalar ishlamaybdi', 'Sensor ishlamayapti',
    'Magnit ishlamayabdi', 'Boshqa'
  ],
  ASNOVA: [
    'Asnova tugadi', 'Asnova yirtildi', "Asnova sifatsiz",
    "Asnova o'rnatilmagan", 'Boshqa'
  ],
};

const DIRECTIONS = {
  MECHANIC: [
    { value: 'MECHANIC', label: 'Mexanik', icon: '🔧' },
    { value: 'ELECTRIC', label: 'Elektrik', icon: '⚡' },
    { value: 'UZLAVYAZ', label: 'Uzlavyaz', icon: '🧵' },
  ],
  ELECTRIC: [
    { value: 'ELECTRIC', label: 'Elektrik', icon: '⚡' },
    { value: 'MECHANIC', label: 'Mexanik', icon: '🔧' },
    { value: 'UZLAVYAZ', label: 'Uzlavyaz', icon: '🧵' },
  ],
  ASNOVA: [
    { value: 'UZLAVYAZ', label: 'Uzlavyaz', icon: '🧵' },
    { value: 'MASTER', label: 'Master', icon: '👔' },
    { value: 'NAZORATCHI', label: 'Nazoratchi', icon: '🛡️' },
  ],
};

const MechanicPanel = ({ user }) => {
  const [calls, setCalls] = useState([]);
  const [filter, setFilter] = useState('ALL');
  const [showCallForm, setShowCallForm] = useState(false);
  const [callForm, setCallForm] = useState({ machine_id: '', signal_type: 'MECHANIC', direction: 'MECHANIC' });
  const [selectedReasons, setSelectedReasons] = useState([]);
  const [customReason, setCustomReason] = useState('');
  const [showReasons, setShowReasons] = useState(false);
  const [forwardCall, setForwardCall] = useState(null);
  const prevCallsRef = useRef([]);

  const token = localStorage.getItem('token');
  const headers = { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' };
  const API = `http://${window.location.hostname}:8000`;

  const playAlert = (signalType) => {
    try {
      const ctx = new (window.AudioContext || window.webkitAudioContext)();
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain);
      gain.connect(ctx.destination);
      gain.gain.value = 0.3;
      if (signalType === 'ELECTRIC') { osc.frequency.value = 660; osc.type = 'sawtooth'; }
      else if (signalType === 'ASNOVA') { osc.frequency.value = 440; osc.type = 'triangle'; }
      else { osc.frequency.value = 520; osc.type = 'sine'; }
      osc.start();
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 1.5);
      osc.stop(ctx.currentTime + 1.5);
    } catch (e) {}
  };

  const fetchCalls = async () => {
    try {
      const res = await fetch(`${API}/mechanic-calls`, { headers });
      if (res.ok) {
        const data = await res.json();
        const newPending = data.filter(c => c.status === 'PENDING');
        const oldPending = prevCallsRef.current.filter(c => c.status === 'PENDING');
        if (newPending.length > oldPending.length) {
          const newCall = newPending.find(nc => !oldPending.some(oc => oc.id === nc.id));
          if (newCall) playAlert(newCall.signal_type || 'MECHANIC');
        }
        prevCallsRef.current = data;
        setCalls(data);
      }
    } catch (e) {}
  };

  useEffect(() => {
    fetchCalls();
    const i = setInterval(fetchCalls, 3000);
    const h = () => fetchCalls();
    window.addEventListener('app-refresh', h);
    return () => { clearInterval(i); window.removeEventListener('app-refresh', h); };
  }, []);

  const updateStatus = async (id, status) => {
    try {
      await fetch(`${API}/mechanic-calls/${id}`, {
        method: 'PUT', headers, body: JSON.stringify({ status })
      });
      fetchCalls();
      emitRefresh();
    } catch (e) {}
  };

  const handleForward = async (callId, newSignalType) => {
    try {
      await fetch(`${API}/mechanic-calls/${callId}`, {
        method: 'PUT', headers, body: JSON.stringify({ status: 'PENDING', signal_type: newSignalType })
      });
      setForwardCall(null);
      fetchCalls();
      emitRefresh();
    } catch (e) {}
  };

  const handleCreateCall = async () => {
    if (!callForm.machine_id) return;
    let reason = selectedReasons.filter(r => r !== 'Boshqa').join(', ');
    if (customReason) reason += (reason ? ', ' : '') + customReason;
    if (!reason) return;
    try {
      const res = await fetch(`${API}/mechanic-calls`, {
        method: 'POST', headers, body: JSON.stringify({ ...callForm, reason })
      });
      if (res.ok) {
        setCallForm({ machine_id: '', signal_type: 'MECHANIC', direction: 'MECHANIC' });
        setSelectedReasons([]);
        setCustomReason('');
        setShowReasons(false);
        setShowCallForm(false);
        fetchCalls();
        emitRefresh();
      }
    } catch (e) {}
  };

  const toggleReason = (reason) => {
    if (reason === 'Boshqa') {
      setSelectedReasons(prev => prev.includes('Boshqa') ? [] : ['Boshqa']);
      setCustomReason('');
    } else {
      setSelectedReasons(prev =>
        prev.includes(reason) ? prev.filter(r => r !== reason) : [...prev.filter(r => r !== 'Boshqa'), reason]
      );
    }
  };

  const handleSignalChange = (type) => {
    const dirs = DIRECTIONS[type] || DIRECTIONS.MECHANIC;
    setCallForm({ ...callForm, signal_type: type, direction: dirs[0].value });
    setSelectedReasons([]);
    setCustomReason('');
    setShowReasons(true);
  };

  const hasOther = selectedReasons.includes('Boshqa');
  const currentReasons = REASONS[callForm.signal_type] || REASONS.MECHANIC;
  const currentDirections = DIRECTIONS[callForm.signal_type] || DIRECTIONS.MECHANIC;

  const statusColors = {
    PENDING: { bg: 'rgba(251,191,36,0.15)', color: '#fbbf24', icon: <Clock size={14} /> },
    IN_PROGRESS: { bg: 'rgba(59,130,246,0.15)', color: '#3b82f6', icon: <Wrench size={14} /> },
    RESOLVED: { bg: 'rgba(34,197,94,0.15)', color: '#22c55e', icon: <CheckCircle size={14} /> },
  };

  const filtered = filter === 'ALL' ? calls : calls.filter(c => c.status === filter);
  const pendingCount = calls.filter(c => c.status === 'PENDING').length;
  const allMachineIds = Array.from({ length: 68 }, (_, i) => `S${i + 1}`);

  const canForward = (call) => {
    if (call.status !== 'IN_PROGRESS') return false;
    return ['MECHANIC', 'ELECTRIC', 'ASNOVA', 'ADMIN', 'MASTER', 'NAZORATCHI', 'UZLAVYAZ'].includes(user.role);
  };

  const forwardTargets = (call) => {
    const targets = [];
    if (call.signal_type === 'MECHANIC') {
      targets.push({ value: 'ELECTRIC', label: 'Elektrikga', icon: '⚡' });
      targets.push({ value: 'ASNOVA', label: 'Uzlavyazga', icon: '🧵' });
    } else if (call.signal_type === 'ELECTRIC') {
      targets.push({ value: 'MECHANIC', label: 'Mexanikka', icon: '🔧' });
      targets.push({ value: 'ASNOVA', label: 'Uzlavyazga', icon: '🧵' });
    } else if (call.signal_type === 'ASNOVA') {
      targets.push({ value: 'MECHANIC', label: 'Mexanikka', icon: '🔧' });
      targets.push({ value: 'ELECTRIC', label: 'Elektrikga', icon: '⚡' });
    }
    return targets;
  };

  const getDirectionLabel = (dir) => {
    const allDirs = [...DIRECTIONS.MECHANIC, ...DIRECTIONS.ASNOVA];
    const found = allDirs.find(d => d.value === dir);
    return found ? found.label : dir;
  };

  return (
    <div style={{ padding: '1.5rem' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem', flexWrap: 'wrap', gap: '8px' }}>
        <h2 style={{ margin: 0, fontSize: '1.5rem', fontWeight: 800, display: 'flex', alignItems: 'center', gap: '10px' }}>
          <Wrench size={24} />
          Chaqiruvlar
          {pendingCount > 0 && (
            <span style={{
              background: '#ef4444', color: 'white', borderRadius: '50%',
              width: '28px', height: '28px', display: 'flex', alignItems: 'center', justifyContent: 'center',
              fontSize: '0.75rem', fontWeight: 800, animation: 'pulse 1.5s infinite'
            }}>{pendingCount}</span>
          )}
        </h2>
        {(user.role === 'MASTER' || user.role === 'ADMIN' || user.role === 'NAZORATCHI' || user.role === 'UZLAVYAZ') && (
          <button onClick={() => { setShowCallForm(!showCallForm); setShowReasons(false); setSelectedReasons([]); setCustomReason(''); }} style={{
            display: 'flex', alignItems: 'center', gap: '6px', padding: '10px 16px',
            background: '#ef4444', color: 'white', border: 'none', borderRadius: '10px',
            cursor: 'pointer', fontWeight: 700, fontSize: '0.85rem'
          }}>
            <AlertTriangle size={16} /> Chaqiruv Yuborish
          </button>
        )}
      </div>

      {showCallForm && (
        <div style={{
          background: 'var(--card)', border: '1px solid var(--panel-border)', borderRadius: '16px',
          padding: '1.5rem', marginBottom: '1.5rem'
        }}>
          <h3 style={{ margin: '0 0 1rem 0', fontSize: '1rem', fontWeight: 700 }}>Yangi Chaqiruv</h3>

          <div style={{ marginBottom: '1rem' }}>
            <label style={labelStyle}>Stanok</label>
            <select className="input-field" style={{ marginTop: '4px' }}
              value={callForm.machine_id}
              onChange={e => setCallForm({ ...callForm, machine_id: e.target.value })}>
              <option value="">Tanlang...</option>
              {allMachineIds.map(id => <option key={id} value={id}>{id}</option>)}
            </select>
          </div>

          <label style={labelStyle}>Signal Turi</label>
          <div style={{ display: 'flex', gap: '8px', marginTop: '8px', marginBottom: '1rem' }}>
            {SIGNAL_TYPES.map(st => (
              <button key={st.value} onClick={() => handleSignalChange(st.value)} style={{
                flex: 1, padding: '12px', borderRadius: '10px', border: '2px solid',
                borderColor: callForm.signal_type === st.value ? st.color : 'rgba(255,255,255,0.1)',
                background: callForm.signal_type === st.value ? `${st.color}22` : 'rgba(255,255,255,0.03)',
                color: callForm.signal_type === st.value ? st.color : 'var(--text-muted)',
                cursor: 'pointer', fontWeight: 700, fontSize: '0.8rem', textAlign: 'center'
              }}>
                <div style={{ fontSize: '1.5rem', marginBottom: '4px' }}>{st.icon}</div>
                {st.label}
              </button>
            ))}
          </div>

          <div style={{
            maxHeight: showReasons ? '800px' : '0',
            overflow: 'hidden',
            transition: 'max-height 0.4s ease, opacity 0.3s ease',
            opacity: showReasons ? 1 : 0,
          }}>
            {/* Yo'naltirish */}
            <label style={labelStyle}>Yo'naltirish</label>
            <div style={{ display: 'flex', gap: '6px', marginTop: '8px', marginBottom: '1rem' }}>
              {currentDirections.map(dir => (
                <button key={dir.value} onClick={() => setCallForm({ ...callForm, direction: dir.value })} style={{
                  flex: 1, padding: '8px', borderRadius: '8px', border: '2px solid',
                  borderColor: callForm.direction === dir.value ? '#00d2ff' : 'rgba(255,255,255,0.1)',
                  background: callForm.direction === dir.value ? 'rgba(0,210,255,0.15)' : 'rgba(255,255,255,0.03)',
                  color: callForm.direction === dir.value ? '#00d2ff' : 'var(--text-muted)',
                  cursor: 'pointer', fontWeight: 600, fontSize: '0.75rem', textAlign: 'center'
                }}>
                  <span style={{ fontSize: '1rem' }}>{dir.icon}</span><br/>{dir.label}
                </button>
              ))}
            </div>

            <label style={labelStyle}>Sababni tanlang (bir nechta tanlash mumkin)</label>
            <div style={{
              display: 'flex', flexWrap: 'wrap', gap: '8px', marginTop: '8px',
              padding: '12px', background: 'rgba(0,0,0,0.2)', borderRadius: '12px'
            }}>
              {currentReasons.map(reason => {
                const isSelected = selectedReasons.includes(reason);
                const isOther = reason === 'Boshqa';
                return (
                  <button key={reason} onClick={() => toggleReason(reason)} style={{
                    padding: '8px 16px', borderRadius: '20px',
                    border: `2px solid ${isSelected ? (isOther ? '#a855f7' : '#22c55e') : 'rgba(255,255,255,0.1)'}`,
                    background: isSelected ? (isOther ? 'rgba(168,85,247,0.2)' : 'rgba(34,197,94,0.15)') : 'rgba(255,255,255,0.03)',
                    color: isSelected ? (isOther ? '#a855f7' : '#22c55e') : 'var(--text-muted)',
                    cursor: 'pointer', fontWeight: 600, fontSize: '0.8rem',
                    transition: 'all 0.2s ease',
                  }}>
                    {isSelected ? '✓ ' : ''}{reason}
                  </button>
                );
              })}
            </div>

            {hasOther && (
              <div style={{ marginTop: '0.75rem' }}>
                <input className="input-field" style={{ marginTop: '4px' }}
                  value={customReason}
                  onChange={e => setCustomReason(e.target.value)}
                  placeholder="Sababni yozing..." autoFocus />
              </div>
            )}
          </div>

          <div style={{ display: 'flex', gap: '8px', marginTop: '1rem' }}>
            <button onClick={handleCreateCall} disabled={!callForm.machine_id || (selectedReasons.length === 0 && !customReason)} style={{
              padding: '10px 20px',
              background: (!callForm.machine_id || (selectedReasons.length === 0 && !customReason)) ? 'rgba(239,68,68,0.3)' : '#ef4444',
              color: 'white', border: 'none', borderRadius: '10px', cursor: 'pointer', fontWeight: 700
            }}>Yuborish</button>
            <button onClick={() => { setShowCallForm(false); setShowReasons(false); setSelectedReasons([]); setCustomReason(''); }} style={{
              padding: '10px 20px', background: 'rgba(255,255,255,0.05)', color: 'var(--text-muted)',
