{"tool":"newFileCreated","path":"frontend/src/App.jsx","content":"import React, { useState, useEffect, useRef } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Login from './components/Login';
import Dashboard from './components/Dashboard';
import AdminPanel from './components/AdminPanel';
import MasterPanel from './components/MasterPanel';
import NazoratchiPanel from './components/NazoratchiPanel';
import UsersPanel from './components/UsersPanel';
import ReportsPanel from './components/ReportsPanel';
import MechanicPanel from './components/MechanicPanel';
import Sidebar from './components/Sidebar';

const SplashScreen = ({ onDone }) => {
  const videoRef = useRef(null);
  const [fadeOut, setFadeOut] = useState(false);

  useEffect(() => {
    const video = videoRef.current;
    if (!video) return;

    const handleEnd = () => {
      setFadeOut(true);
      setTimeout(() => onDone(), 500);
    };

    video.addEventListener('ended', handleEnd);
    const timer = setTimeout(() => {
      setFadeOut(true);
      setTimeout(() => onDone(), 6000);
    }, 6000);

    return () => {
      video.removeEventListener('ended', handleEnd);
      clearTimeout(timer);
    };
  }, [onDone]);

  return (
    <div className={`splash-screen ${fadeOut ? 'splash-fade-out' : ''}`}>
      <video
        ref={videoRef}
        src="/splash.mp4"
        autoPlay
        muted
        playsInline
        className="splash-video"
      />
    </div>
  );
};

function App() {
  const [user, setUser] = useState(JSON.parse(localStorage.getItem('user')) || null);
  const [activeTab, setActiveTab] = useState('run');
  const [showSplash, setShowSplash] = useState(true);

  const handleLogin = (userData) => {
    localStorage.setItem('user', JSON.stringify(userData));
    setUser(userData);
  };

  const handleLogout = () => {
    localStorage.removeItem('user');
    localStorage.removeItem('token');
    setUser(null);
    setActiveTab('run');
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'run': return <Dashboard user={user} />;
      case 'report': return <ReportsPanel user={user} />;
      case 'mechanic': return <MechanicPanel user={user} />;
      case 'admin': return <AdminPanel user={user} />;
      case 'master': return <MasterPanel user={user} />;
      case 'nazoratchi': return <NazoratchiPanel user={user} />;
      case 'users': return <UsersPanel user={user} />;
      default: return <Dashboard user={user} />;
    }
  };

  if (showSplash) {
    return <SplashScreen onDone={() => setShowSplash(false)} />;
  }

  return (
    <Router>
      <Routes>
        <Route path="/login" element={!user ? <Login onLogin={handleLogin} /> : <Navigate to="/" />} />
        <Route path="/*" element={
          user ? (
            <div className="app-container app-appear">
              <Sidebar user={user} activeTab={activeTab} onTabChange={setActiveTab} onLogout={handleLogout} />
              <div className="main-content">
                {renderContent()}
              </div>
            </div>
          ) : (
            <Navigate to="/login" />
          )
        } />
      </Routes>
    </Router>
  );
}

