{"tool":"newFileCreated","path":"frontend/src/index.css","content":":root {
  --bg: #05070a;
  --bg-panel: #0b0f1a;
  --card: rgba(15, 23, 42, 0.6);
  --panel-border: rgba(255, 255, 255, 0.08);
  --primary: #00d2ff;
  --neon-blue: #00d2ff;
  --neon-green: #39ff14;
  --neon-red: #ff3131;
  --neon-yellow: #ffea00;
  --neon-violet: #a855f7;
  --text-main: #f8fafc;
  --text-muted: #64748b;
  --glass: rgba(10, 15, 25, 0.7);
}

html, body {
  margin: 0; padding: 0;
  background: var(--bg);
  color: var(--text-main);
  font-family: 'Inter', sans-serif;
  overflow: hidden;
  -webkit-text-size-adjust: 100%;
  -webkit-tap-highlight-color: transparent;
  width: 100%; height: 100%;
}

* { box-sizing: border-box; }

/* ═══ SPLASH ═══ */
.splash-screen {
  position: fixed; top: 0; left: 0; right: 0; bottom: 0;
  background: #000;
  z-index: 9999;
  display: flex; align-items: center; justify-content: center;
  transition: opacity 0.6s ease;
  overflow: hidden;
}
.splash-screen::before {
  content: '';
  position: absolute; top: 0; left: 0; right: 0; bottom: 0;
  background: linear-gradient(135deg, #0f0c29, #302b63, #24243e, #0f0c29);
  background-size: 400% 400%;
  animation: gradientShift 6s ease infinite;
  z-index: 0;
}
@keyframes gradientShift {
  0% { background-position: 0% 50%; }
  50% { background-position: 100% 50%; }
  100% { background-position: 0% 50%; }
}
.splash-screen.splash-fade-out {
  opacity: 0;
  pointer-events: none;
}
.splash-video {
  position: relative; z-index: 1;
  width: 100%; height: 100%;
  object-fit: contain;
}

/* ═══ APP ═══ */
.app-appear { animation: app-fade-in 0.8s ease forwards; }
@keyframes app-fade-in {
  0% { opacity: 0; transform: scale(0.98); }
  100% { opacity: 1; transform: scale(1); }
}
.app-container {
  display: flex;
  height: 100vh; height: 100dvh;
  width: 100vw; overflow: hidden;
}

/* ═══ DESKTOP SIDEBAR ═══ */
.sidebar-desktop {
  width: 240px; min-width: 240px;
  background: #111827;
  border-right: 1px solid var(--panel-border);
  display: flex; flex-direction: column;
  padding: 1rem;
  overflow-y: auto; overflow-x: hidden;
}

/* ═══ MOBILE BOTTOM BAR ═══ */
.mobile-bottom-bar { display: none; }

@media (max-width: 768px) {
  .app-container {
    flex-direction: column;
    height: 100dvh; width: 100vw;
    overflow: hidden;
  }
  .sidebar-desktop { display: none; }
  .mobile-bottom-bar {
    display: flex;
    position: fixed; bottom: 0; left: 0; right: 0;
    z-index: 999;
    background: rgba(17, 24, 39, 0.92);
    backdrop-filter: blur(20px) saturate(180%);
    -webkit-backdrop-filter: blur(20px) saturate(180%);
    border-top: 0.5px solid rgba(255, 255, 255, 0.1);
    padding-bottom: env(safe-area-inset-bottom, 0px);
  }
  .mobile-bottom-bar-inner {
    display: flex;
    justify-content: space-around;
    align-items: flex-end;
    padding: 6px 4px 4px;
    width: 100%;
  }
  .mobile-tab-btn {
    display: flex; flex-direction: column;
    align-items: center; gap: 2px;
    background: none; border: none; cursor: pointer;
    padding: 4px 6px; border-radius: 12px;
    color: rgba(148, 163, 184, 0.7);
    transition: all 0.2s ease;
    min-width: 52px;
    -webkit-tap-highlight-color: transparent;
  }
  .mobile-tab-btn:active { transform: scale(0.9); }
  .mobile-tab-icon-wrap {
    display: flex; align-items: center; justify-content: center;
    width: 28px; height: 28px; border-radius: 50%;
    transition: all 0.25s ease;
  }
  .mobile-tab-btn.active .mobile-tab-icon-wrap {
    background: rgba(0, 210, 255, 0.15);
    color: var(--primary);
  }
  .mobile-tab-btn.active { color: var(--primary); }
  .mobile-tab-label {
    font-size: 0.55rem; font-weight: 600;
    letter-spacing: 0.2px; white-space: nowrap;
    overflow: hidden; text-overflow: ellipsis; max-width: 64px;
  }
  .mobile-tab-btn.active .mobile-tab-label {
    color: var(--primary); font-weight: 700;
  }
  .mobile-tab-btn.logout-btn { color: rgba(239, 68, 68, 0.7); }
  .mobile-tab-btn.logout-btn:active { color: #ef4444; }
}

/* ═══ STAT WIDGETS ═══ */
.stat-widget {
  background: var(--card); border-radius: 1rem;
  padding: 1.25rem; margin-bottom: 1rem;
  border: 1px solid var(--panel-border);
}
.stat-value { font-size: 2rem; font-weight: 800; line-height: 1; }
.stat-label {
  color: var(--text-muted); font-size: 0.875rem;
  text-transform: uppercase; letter-spacing: 1px;
}
@media (max-width: 768px) {
  .stat-widget { padding: 0.5rem; margin-bottom: 0; border-radius: 0.75rem; }
  .stat-value { font-size: 1.2rem; }
  .stat-label { font-size: 0.6rem; letter-spacing: 0; }
}

/* ═══ MAIN CONTENT ═══ */
.main-content {
  flex: 1; padding: 1rem; background: #0b0f1a;
  overflow: auto; display: flex; flex-direction: column;
  min-width: 0; min-height: 0;
}
@media (max-width: 768px) {
  .main-content {
    padding: 0.25rem; flex: 1; overflow: hidden;
    display: flex; flex-direction: column;
    min-height: 0; padding-bottom: 72px;
  }
}

/* ═══ FACTORY MAP ═══ */
.factory-map-container {
  flex: 1; overflow: auto; border-radius: 16px; padding: 8px;
}
@media (max-width: 768px) {
  .factory-map-container {
    border-radius: 8px; padding: 0;
    overflow: auto; -webkit-overflow-scrolling: touch;
    flex: 1; min-height: 0;
  }
}
.factory-bg {
  position: relative; width: 1200px; height: 800px;
  background: #111827; border-radius: 8px;
  border: 3px solid #334155;
  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.5);
  background-image:
    linear-gradient(rgba(255,255,255,0.02) 1px, transparent 1px),
    linear-gradient(90deg, rgba(255,255,255,0.02) 1px, transparent 1px);
  background-size: 25px 25px;
}
@media (max-width: 768px) {
  .factory-bg {
    width: 1200px; height: 800px;
    transform: scale(0.45);
    transform-origin: top left;
    border-radius: 6px; border-width: 2px;
  }
}
@media (max-width: 480px) {
  .factory-bg { transform: scale(0.35); transform-origin: top left; }
}

/* ═══ MACHINE NODES ═══ */
.machine-node {
  position: absolute; width: 48px; height: 48px;
  border-radius: 12px;
  display: flex; align-items: center; justify-content: center;
  cursor: pointer;
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  border: 1px solid rgba(255, 255, 255, 0.1);
  backdrop-filter: blur(4px);
  touch-action: manipulation;
}
.machine-node:hover {
  transform: scale(1.2) translateY(-5px);
  z-index: 10; box-shadow: 0 0 20px rgba(0, 210, 255, 0.5);
}
.machine-node.is-focused {
  border-color: var(--primary);
  box-shadow: 0 0 30px rgba(0, 210, 255, 0.6);
  z-index: 5;
}
.smart-pulse {
  position: absolute; width: 100%; height: 100%;
  border: 2px solid var(--primary); border-radius: 50%;
  animation: smart-ripple 1.5s infinite; pointer-events: none;
}
@keyframes smart-ripple {
  0% { transform: scale(0.5); opacity: 1; }
  100% { transform: scale(2.5); opacity: 0; }
}
.machine-node.running {
  background: rgba(57, 255, 20, 0.1);
  color: var(--neon-green); border-color: var(--neon-green);
  box-shadow: 0 0 10px rgba(57, 255, 20, 0.2);
  animation: neon-pulse-green 2s infinite;
}
.machine-node.stopped {
  background: rgba(255, 49, 49, 0.1);
  color: var(--neon-red); border-color: var(--neon-red);
}
.machine-node.warning {
  background: rgba(255, 234, 0, 0.1);
  color: var(--neon-yellow); border-color: var(--neon-yellow);
  animation: neon-pulse-yellow 2s infinite;
}
.machine-node.searching {
  background: rgba(168, 85, 247, 0.2);
  color: #c084fc; border-color: #a855f7;
  box-shadow: 0 0 15px rgba(168, 85, 247, 0.4);
  animation: neon-pulse-violet 2s infinite;
}
@keyframes neon-pulse-green {
  0% { box-shadow: 0 0 5px rgba(57, 255, 20, 0.4); }
  50% { box-shadow: 0 0 25px rgba(57, 255, 20, 0.7), 0 0 40px rgba(57, 255, 20, 0.3); }
  100% { box-shadow: 0 0 5px rgba(57, 255, 20, 0.4); }
}
@keyframes neon-pulse-violet {
  0% { box-shadow: 0 0 5px rgba(168, 85, 247, 0.4); }
  50% { box-shadow: 0 0 25px rgba(168, 85, 247, 0.7), 0 0 40px rgba(168, 85, 247, 0.3); }
  100% { box-shadow: 0 0 5px rgba(168, 85, 247, 0.4); }
}

/* ═══ TAB SWITCHER ═══ */
.tab-switcher {
  display: flex; background: rgba(255, 255, 255, 0.05);
  border-radius: 8px; padding: 3px; gap: 3px;
}
.tab-switcher button {
  background: transparent; border: none;
  color: var(--text-muted); font-size: 0.65rem;
  font-weight: 800; padding: 5px 12px;
  border-radius: 6px; cursor: pointer; transition: 0.2s;
}
.tab-switcher button.active {
  background: var(--primary); color: white;
  box-shadow: 0 0 10px var(--primary);
}

/* ═══ DIAG PANEL ═══ */
.diag-panel { display: flex; flex-direction: column; gap: 1.25rem; margin-bottom: 2rem; }
.diag-item { display: flex; flex-direction: column; gap: 8px; }
.diag-label {
  font-size: 0.75rem; font-weight: 600;
  color: var(--text-muted); display: flex; justify-content: space-between;
}
.diag-label span { color: var(--text); font-family: monospace; }
.diag-bar-bg {
  height: 8px; background: rgba(255, 255, 255, 0.05);
  border-radius: 4px; overflow: hidden;
}
.diag-bar {
  height: 100%; border-radius: 4px;
  transition: width 0.5s ease-in-out;
}
.diag-bar.ram {
  background: linear-gradient(90deg, #38bdf8, #0ea5e9);
  box-shadow: 0 0 10px rgba(56, 189, 248, 0.3);
}
.diag-bar.rom {
  background: linear-gradient(90deg, #a855f7, #8b5cf6);
  box-shadow: 0 0 10px rgba(168, 85, 247, 0.3);
}

/* ═══ MODAL ═══ */
.modal-overlay {
  position: fixed; top: 0; left: 0; right: 0; bottom: 0;
  background: rgba(0, 0, 0, 0.7);
  backdrop-filter: blur(4px);
  display: flex; align-items: center; justify-content: center;
  z-index: 100; padding: 1rem;
}
.modal-content {
  background: var(--bg-panel);
  border: 1px solid var(--panel-border);
  border-radius: 24px; padding: 2rem;
  width: 92%; max-width: 450px;
  max-height: 85vh; overflow-y: auto;
  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.5);
}
@media (max-width: 768px) {
  .modal-overlay { padding: 0; align-items: flex-end; }
  .modal-content {
    width: 100%; max-width: 100%;
    border-radius: 24px 24px 0 0;
    padding: 1.25rem;
    max-height: 80vh; max-height: 80dvh;
  }
}

/* ═══ FORM ELEMENTS ═══ */
.input-field {
  width: 100%; padding: 12px 16px;
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid var(--panel-border);
  border-radius: 12px; color: var(--text-main);
